  if (!token) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  // TODO: Verify JWT token
  // This is where you'd verify the token with jsonwebtoken
  req.user = { id: 1, role: 'user' }; // Placeholder
  next();
};

// === Endpoints ===

// Health check (no auth required, public)
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Get users (requires authentication)
app.get('/users', 
  authMiddleware, // Verify user is authenticated
  query('limit').optional().isInt({ max: 100 }).toInt(),
  (req, res) => {
    // Validate input
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    // Log access to sensitive data
    console.log(`[AUDIT] User ${req.user.id} accessed /users from ${req.ip}`);

    // Return user data
    res.json([
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ]);
  }
);

// === Error Handler ===
app.use((err, req, res, next) => {
  console.error('[ERROR]', new Date().toISOString(), err.message);
  console.error(err.stack);
  res.status(500).json({ 
    error: 'Internal Server Error'
    // Never expose: err.message, err.stack, etc.
  });
});

// === Not found handler ===
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
